import{_ as a,o as i,c as e,ah as n}from"./chunks/framework.BNo2o5Ln.js";const k=JSON.parse('{"title":"监控与运维","description":"","frontmatter":{"title":"监控与运维","order":3},"headers":[],"relativePath":"server/db/operations/monitoring.md","filePath":"server/db/operations/monitoring.md"}'),t={name:"server/db/operations/monitoring.md"};function l(h,s,d,r,p,o){return i(),e("div",null,[...s[0]||(s[0]=[n(`<h1 id="监控与运维" tabindex="-1">监控与运维 <a class="header-anchor" href="#监控与运维" aria-label="Permalink to “监控与运维”">​</a></h1><p>数据库监控是保障稳定运行的前提。通过监控可以及时发现性能瓶颈、容量预警、异常行为，为运维决策提供数据支持。</p><h2 id="核心监控指标" tabindex="-1">核心监控指标 <a class="header-anchor" href="#核心监控指标" aria-label="Permalink to “核心监控指标”">​</a></h2><h3 id="可用性指标" tabindex="-1">可用性指标 <a class="header-anchor" href="#可用性指标" aria-label="Permalink to “可用性指标”">​</a></h3><p>可用性是数据库服务最基础的指标，通常用 SLA（Service Level Agreement）衡量。数据库可用性 = (总时间 - 不可用时间) / 总时间。生产环境的可用性目标通常设定为 99.9% 或更高，意味着每年不可用时间不超过 8.76 小时。</p><p>监控数据库可用性的方法包括定期探测连接、检查服务进程状态、监控应用层错误日志。使用如 Prometheus + Alertman、Grafana、Zabbix 等监控工具，配置数据库不可用时的告警。</p><h3 id="性能指标" tabindex="-1">性能指标 <a class="header-anchor" href="#性能指标" aria-label="Permalink to “性能指标”">​</a></h3><p>QPS（Queries Per Second）和 TPS（Transactions Per Second）是衡量数据库负载的核心指标。QPS 表示每秒执行的查询数，TPS 表示每秒提交的事务数。对于 OLTP 系统，TPS 更能反映业务压力。监控 QPS/TPS 的趋势，可以评估数据库的负载情况和容量规划。</p><p>响应时间分为平均响应时间和 P99 响应时间。平均响应时间是所有查询的执行时间平均值，P99 响应时间是 99% 的查询的响应时间上限。P99 更能反映用户体验，因为长尾查询影响的是少数用户但体验极差。建议监控 P95、P99、P999 三个分位值，全面了解查询分布。</p><p>并发连接数反映当前活跃的连接数量，应该与 max_connections 参数对比。连接数接近上限会导致新连接被拒绝，需要及时扩容或优化连接池。连接池的配置同样重要，过大连接数会消耗大量内存，过小会导致应用等待连接。</p><h3 id="资源指标" tabindex="-1">资源指标 <a class="header-anchor" href="#资源指标" aria-label="Permalink to “资源指标”">​</a></h3><p>CPU 使用率需要关注长期趋势而非瞬时峰值。数据库的 CPU 使用率持续高于 80% 说明资源紧张，需要优化查询或扩容。CPU 使用率的突增可能由异常查询、备份任务、统计信息收集等引起，需要定位具体原因。</p><p>内存使用率重点关注缓冲池命中率。InnoDB 缓冲池命中率 = (1 - innodb_buffer_pool_reads / innodb_buffer_pool_read_requests) × 100%。正常值应该在 99% 以上，低于 95% 说明内存不足，需要增加缓冲池大小或优化查询减少磁盘 I/O。操作系统的内存使用率同样重要，swap 使用是危险的信号，说明物理内存不足。</p><p>磁盘 I/O 包括 IOPS、吞吐量、等待时间。监控磁盘队列长度、平均等待时间、使用率，使用率持续高于 80% 说明磁盘是瓶颈。对于 SSD，更关注 IOPS；对于机械硬盘，更关注顺序读写的吞吐量。tempdb 的增长和临时表数量也是间接的 I/O 指标，过多的磁盘临时表说明查询需要优化。</p><p>网络流量通常不是数据库的瓶颈，但需要关注异常流量。备库的复制延迟与网络带宽相关，如果复制延迟持续增长，可能是网络带宽不足或主库写入量太大。</p><h2 id="mysql-监控" tabindex="-1">MySQL 监控 <a class="header-anchor" href="#mysql-监控" aria-label="Permalink to “MySQL 监控”">​</a></h2><h3 id="状态变量监控" tabindex="-1">状态变量监控 <a class="header-anchor" href="#状态变量监控" aria-label="Permalink to “状态变量监控”">​</a></h3><p>MySQL 的 <code>SHOW STATUS</code> 命令提供了丰富的状态变量，是监控数据的主要来源。<code>Questions</code> 表示服务器执行的所有语句数量，<code>Com_select</code>、<code>Com_insert</code>、<code>Com_update</code>、<code>Com_delete</code> 分别表示各类操作的执行次数，通过这些变量可以计算 QPS 和读写比例。</p><p><code>Slow_queries</code> 表示慢查询数量，如果该值持续增长，说明存在性能问题。<code>Connections</code> 表示历史连接总数，<code>Max_used_connections</code> 表示同时使用的最大连接数，这两个值可以评估连接数配置是否合理。<code>Threads_connected</code> 表示当前连接数，<code>Threads_running</code> 表示活跃的连接数，活跃连接数持续过高说明存在大量长事务或锁等待。</p><p><code>Innodb_row_lock_waits</code> 表示行锁等待次数，<code>Innodb_row_lock_time</code> 表示行锁等待总时间。锁等待次数多说明存在锁竞争，需要检查事务隔离级别、索引设计、SQL 写法。<code>Handler_read_next</code> 表示通过索引顺序读取的行数，该值过大说明索引效率低或没有使用索引。</p><h3 id="performance-schema" tabindex="-1">Performance Schema <a class="header-anchor" href="#performance-schema" aria-label="Permalink to “Performance Schema”">​</a></h3><p>Performance Schema 是 MySQL 5.5+ 引入的性能监控组件，提供了底层的性能事件统计。<code>events_statements_summary_by_digest</code> 表记录了每种 SQL 语句的执行次数、执行时间、锁等待时间、扫描行数等统计信息，是分析 SQL 性能的金矿。</p><div class="language-sql"><button title="Copy Code" class="copy"></button><span class="lang">sql</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">-- 查看执行时间最长的 10 条 SQL</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">SELECT</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> digest_text, count_star, avg_timer_wait</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">/</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">1000000000000</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> as</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> avg_sec,</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  sum_timer_wait</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">/</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">1000000000000</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> as</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> total_sec</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">FROM</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> performance_schema</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">.</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">events_statements_summary_by_digest</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">ORDER BY</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> sum_timer_wait </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">DESC</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">LIMIT</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 10</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">;</span></span></code></pre></div><p><code>file_summary_by_instance</code> 表记录了每个文件的 I/O 操作统计，可以定位热点文件。<code>table_io_waits_summary_by_table</code> 表记录了每个表的 I/O 等待统计，可以定位热点表。这些信息对性能优化有直接指导意义。</p><h3 id="主从复制监控" tabindex="-1">主从复制监控 <a class="header-anchor" href="#主从复制监控" aria-label="Permalink to “主从复制监控”">​</a></h3><p>主从复制是 MySQL 高可用的基础方案，监控复制状态至关重要。<code>SHOW SLAVE STATUS</code> 命令的输出包含复制状态的关键信息。<code>Seconds_Behind_Master</code> 表示复制延迟，正常值应该接近 0，如果持续增长说明备库同步跟不上，需要检查备库性能和网络带宽。</p><p><code>Slave_IO_Running</code> 和 <code>Slave_SQL_Running</code> 应该都是 Yes，如果是 No 说明复制线程停止，需要查看错误信息。<code>Last_Error</code> 和 <code>Last_SQL_Error</code> 字段记录了最近的错误信息，常见的错误包括主键冲突、找不到表、连接中断等。<code>Relay_Log_Space</code> 表示中继日志大小，过大说明备库执行慢，需要排查。</p><p>对于 GTID 复制模式，监控 <code>Retrieved_Gtid_Set</code> 和 <code>Executed_Gtid_Set</code> 可以确认复制的进度。<code>Executed_Gtid_Set</code> 应该持续增长，如果停滞说明备库执行停止。</p><h2 id="postgresql-监控" tabindex="-1">PostgreSQL 监控 <a class="header-anchor" href="#postgresql-监控" aria-label="Permalink to “PostgreSQL 监控”">​</a></h2><h3 id="统计视图监控" tabindex="-1">统计视图监控 <a class="header-anchor" href="#统计视图监控" aria-label="Permalink to “统计视图监控”">​</a></h3><p>PostgreSQL 提供了丰富的统计视图，<code>pg_stat_activity</code> 显示当前活动会话，<code>pg_stat_database</code> 显示数据库级别的统计，<code>pg_stat_user_tables</code> 显示用户表的统计，<code>pg_stat_user_indexes</code> 显示用户索引的统计。</p><p><code>pg_stat_activity</code> 的 <code>state</code> 字段表示会话状态：active 表示正在执行查询，idle 表示空闲，idle in transaction 表示空闲但在事务中，后者是需要关注的，可能意味着应用忘记提交事务。<code>query_start</code> 字段表示查询开始时间，可以识别长查询。</p><div class="language-sql"><button title="Copy Code" class="copy"></button><span class="lang">sql</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">-- 查找长时间运行的查询</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">SELECT</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> pid, </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">now</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">() </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> query_start </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">as</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> duration, query</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">FROM</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> pg_stat_activity</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">WHERE</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> state</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> =</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;active&#39;</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">AND</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> now</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">() </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> query_start </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> interval </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;5 minutes&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">;</span></span></code></pre></div><p><code>pg_stat_database</code> 的 <code>blks_read</code> 和 <code>blks_hit</code> 表示磁盘读取和缓存读取次数，缓存命中率 = blks_hit / (blks_hit + blks_read)。正常值应该在 99% 以上，低于 95% 说明 shared_buffers 配置偏小或查询需要优化。</p><p><code>pg_stat_user_tables</code> 的 <code>seq_scan</code> 和 <code>idx_scan</code> 表示顺序扫描和索引扫描次数，如果某个表的 seq_scan 很高而 idx_scan 很低，说明缺少合适的索引。<code>n_tup_ins</code>、<code>n_tup_upd</code>、<code>n_tup_del</code> 表示插入、更新、删除的行数，<code>n_tup_hot_upd</code> 表示 HOT 更新的行数，HOT 更新避免了索引维护，是 PostgreSQL 的优化特性。</p><h3 id="复制监控" tabindex="-1">复制监控 <a class="header-anchor" href="#复制监控" aria-label="Permalink to “复制监控”">​</a></h3><p>PostgreSQL 的流复制监控通过 <code>pg_stat_replication</code> 视图。<code>sync_state</code> 表示同步状态：sync 表示同步复制，potential 表示潜在同步复制（当同步备库故障时提升），async 表示异步复制。对于高可用要求高的场景，应该有至少一个 sync 备库。</p><p><code>replay_lag</code> 表示备库的重放延迟，<code>flush_lag</code> 表示备库的刷盘延迟，这两个值应该保持在秒级。<code>sent_lsn</code> 和 <code>replay_lsn</code> 表示发送和重放的 LSN 位置，两者的差值表示备库待应用的 WAL 量。</p><h2 id="告警策略" tabindex="-1">告警策略 <a class="header-anchor" href="#告警策略" aria-label="Permalink to “告警策略”">​</a></h2><h3 id="告警级别" tabindex="-1">告警级别 <a class="header-anchor" href="#告警级别" aria-label="Permalink to “告警级别”">​</a></h3><p>告警分为紧急、重要、警告三个级别。紧急告警需要立即处理，例如数据库不可用、主从复制停止、磁盘空间不足 10%。重要告警需要尽快处理，例如慢查询突增、复制延迟超过 1 分钟、连接数接近上限。警告告警可以关注，例如备份失败、查询缓存命中率下降、锁等待增加。</p><h3 id="告警收敛" tabindex="-1">告警收敛 <a class="header-anchor" href="#告警收敛" aria-label="Permalink to “告警收敛”">​</a></h3><p>告警收敛避免告警风暴，影响运维体验。相同告警在一段时间内只发送一次通知，或者在问题恢复前不再重复通知。告警分组将相关告警合并发送，例如同一个数据库的多个指标异常可以合并为一条告警。</p><h3 id="告警通道" tabindex="-1">告警通道 <a class="header-anchor" href="#告警通道" aria-label="Permalink to “告警通道”">​</a></h3><p>告警通道包括邮件、短信、钉钉、Slack、PagerDuty 等。紧急告警应该通过多种通道发送，确保及时接收。警告告警可以通过邮件或即时消息发送。告警内容应该清晰说明问题、影响范围、建议操作，避免需要登录系统查看详情。</p><h2 id="日常维护" tabindex="-1">日常维护 <a class="header-anchor" href="#日常维护" aria-label="Permalink to “日常维护”">​</a></h2><h3 id="数据清理" tabindex="-1">数据清理 <a class="header-anchor" href="#数据清理" aria-label="Permalink to “数据清理”">​</a></h3><p>数据持续增长会消耗存储空间和降低性能，定期清理过期数据是必要的维护操作。对于分区表，可以直接删除过期分区。对于普通表，使用 DELETE 删除数据后需要执行 <code>OPTIMIZE TABLE</code> 回收空间。对于时序数据，考虑使用 DROP PARTITION 或 TRUNCATE PARTITION，比 DELETE 高效得多。</p><div class="language-sql"><button title="Copy Code" class="copy"></button><span class="lang">sql</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">-- 删除三个月前的订单（按月分区）</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">ALTER</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> TABLE</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> orders </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">DROP</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> PARTITION</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> p202301;</span></span></code></pre></div><p>定期清理 binlog 和 WAL 日志，避免占用过多磁盘空间。MySQL 的 <code>expire_logs_days</code> 参数控制 binlog 保留天数，PostgreSQL 的 <code>archive_cleanup_command</code> 控制归档 WAL 的清理。</p><h3 id="统计信息收集" tabindex="-1">统计信息收集 <a class="header-anchor" href="#统计信息收集" aria-label="Permalink to “统计信息收集”">​</a></h3><p>查询优化器依赖统计信息选择执行计划，统计信息不准确会导致错误的执行计划。对于频繁变更的表，需要定期收集统计信息。MySQL 的 <code>ANALYZE TABLE</code> 命令更新统计信息，PostgreSQL 的 <code>ANALYZE</code> 命令类似。可以配置定时任务在业务低峰期执行。</p><div class="language-sql"><button title="Copy Code" class="copy"></button><span class="lang">sql</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">-- MySQL 更新表统计信息</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">ANALYZE </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">TABLE</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> orders;</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">-- PostgreSQL 更新数据库统计信息</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">ANALYZE;</span></span></code></pre></div><p>统计信息收集的频率取决于数据变更频率，对于写入量大的表，每天收集一次；对于写入量小的表，每周收集一次即可。</p><h3 id="索引维护" tabindex="-1">索引维护 <a class="header-anchor" href="#索引维护" aria-label="Permalink to “索引维护”">​</a></h3><p>索引碎片会影响查询性能，定期重建索引可以消除碎片。MySQL 5.6+ 的 Online DDL 支持在线重建索引，不阻塞读写。<code>ALTER TABLE t ENGINE=InnoDB</code> 重建表并重建所有索引。PostgreSQL 的 <code>REINDEX INDEX</code> 重建单个索引，<code>REINDEX TABLE</code> 重建表的所有索引。</p><div class="language-sql"><button title="Copy Code" class="copy"></button><span class="lang">sql</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">-- MySQL 在线重建表</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">ALTER</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> TABLE</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> orders ENGINE</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">InnoDB;</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">-- PostgreSQL 重建索引</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">REINDEX </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">TABLE</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> orders;</span></span></code></pre></div><p>索引维护应该在业务低峰期执行，因为重建索引会消耗大量 I/O 和 CPU 资源。对于大表，可以考虑使用 <code>pt-online-schema-change</code> 工具在线变更表结构。</p><p>数据库监控是持续改进的基础，建立完善的监控体系、配置合理的告警策略、执行定期的维护操作，才能保持数据库的稳定运行和良好性能。</p>`,59)])])}const g=a(t,[["render",l]]);export{k as __pageData,g as default};
